}

#define MQ_PIN 34
#define DUST_LED 12
#define DUST_VO 35

void setup() {
  pinMode(DUST_LED, OUTPUT);
}

float readDust() {
  digitalWrite(DUST_LED, LOW); // Turn on LED
  delayMicroseconds(280);
  float val = analogRead(DUST_VO);
  delayMicroseconds(40);
  digitalWrite(DUST_LED, HIGH); // Turn off LED
  return val;
}

void loop() {
  float dust = readDust();
  int gas = analogRead(MQ_PIN);
  // Publish readings to cloud metrics dashboard
  delay(2000);
}

#include <ModbusMaster.h>

#define MAX485_DE 4
ModbusMaster node;

void preTransmission() { digitalWrite(MAX485_DE, 1); }
void postTransmission() { digitalWrite(MAX485_DE, 0); }

void setup() {
  pinMode(MAX485_DE, OUTPUT);
  Serial2.begin(9600, SERIAL_8N1, 16, 17);
  node.begin(1, Serial2); // Device ID 1
  node.preTransmission(preTransmission);
  node.postTransmission(postTransmission);
}
void loop() {
  node.readHoldingRegisters(0x0000, 2);
  delay(1000);
}

#define PH_PIN 32

float getPH() {
  int raw = analogRead(PH_PIN);
  float voltage = raw * 3.3 / 4095.0;
  // Calibrate scale: pH 7 = 2.5V, Slope = -5.7 pH/V
  float pH = 7.0 + ((2.5 - voltage) / 0.18);
  return pH;
}
void setup() {}
void loop() {
  float value = getPH();
  delay(2000);
}

